from smolagents import CodeAgent
from vex import verify

search_agent = CodeAgent(tools=["duckduckgo-search"])
summarize_agent = CodeAgent(tools=["python"])

@verify(checks=["source_verification", "recency_check"])
def verified_search(query):
    return search_agent.run(query)

@verify(checks=["claim_accuracy", "bias_detection"])
def verified_summarize(search_results):
    return summarize_agent.run(search_results)

# Pipeline
sources = verified_search("Latest EV battery tech")
summary = verified_summarize(sources)
print(summary)
